                          {areaPath && <path d={areaPath} fill="url(#chart-gradient)" />}

                          {/* Volume bars (bottom 15%) - only show for Price chart */}
                          {chartType === 'price' && points.map((p, idx) => {
                            const barHeight = (p.data.volume / maxVol) * 35;
