                                x2={p.x} 
                                y2={yEnd} 
                                stroke="currentColor" 
                                className="text-slate-200 dark:text-slate-850" 
                                strokeWidth="2.5" 
                              />
                            );
                          })}

                          {/* SVG stroke path */}
                          {linePath && (
                            <path 
                              d={linePath} 
                              fill="none" 
                              stroke={chartType === 'price' ? '#3b82f6' : '#a855f7'} 
                              strokeWidth="2.5" 
                              strokeLinecap="round" 
                              strokeLinejoin="round" 
                              className={`drop-shadow-[0_2px_8px_${chartType === 'price' ? 'rgba(59,130,246,0.3)' : 'rgba(168,85,247,0.3)'}]`}
                            />
