                                const el = document.elementFromPoint(touch.clientX, touch.clientY);
                                const idxAttr = el?.getAttribute('data-chart-idx');
                                if (idxAttr != null) {
                                  const i = Number(idxAttr);
                                  if (chartPoints[i]) setHoveredPoint(chartPoints[i]);
                                }
                              }}
                              data-chart-idx={idx}
                            />
                          ))}
                        </div>
