                              />
                            </div>
                            {/* Growth badge */}
                            {profGrowth !== null && (
                              <span className={`text-[8px] font-black mt-0.5 ${profGrowth >= 0 ? 'text-emerald-500' : 'text-red-400'}`}>
                                {profGrowth >= 0 ? '+' : ''}{profGrowth.toFixed(0)}%
                              </span>
                            )}
                            <span className="text-[8px] text-slate-400 font-bold truncate w-full text-center">
                              {y.date.slice(0, 4)}
                            </span>
                          </div>
