                    <span className="text-xs font-semibold text-slate-400">52-Week Low</span>
                    <span className="text-sm font-bold text-red-500">₹{ratios.fiftyTwoWeekLow?.toLocaleString('en-IN', { maximumFractionDigits: 2 })}</span>
                  </div>
                </div>
              </div>
