                    >
                      <div>
                        <div className="flex items-center justify-between gap-4 mb-2.5">
                          <span className="text-[9px] font-extrabold uppercase tracking-wider text-blue-600 dark:text-blue-400 bg-blue-500/10 px-1.5 py-0.5 rounded">
