                      </div>
                    </a>
                  ))}
                </div>
              )}
            </div>
            
          </div>
          </div>

          {/* 2. AI Outlook & Analysis */}
          <div id="section-ai" className="scroll-mt-24">
          <AIForecastDashboard data={data} displayPrice={displayPrice} theme={theme} />
          </div>

