"use client";

import React, { useEffect, useState, useCallback, useRef, useMemo } from 'react';
import { useSearchParams } from 'next/navigation';
import Link from 'next/link';
import dynamic from 'next/dynamic';
import {
  ArrowLeft,
  TrendingUp,
  TrendingDown,
  RefreshCw,
  Search,
  ChevronRight,
  Layers,
  Sparkles,
  Trash2,
  Plus,
  Star,
  Sun,
  Moon,
  Scale,
  PieChart,
  AlertTriangle,
  CheckCircle,
  FileText,
  ExternalLink,
  Newspaper,
  Grid,
  Save,
  Bell,
  Percent,
  Activity,
  Play,
  Pause,
  Sliders,
  X,
  Check,
  ChevronDown,
  Lock,
  Unlock
} from 'lucide-react';
import { DEFAULT_SYMBOLS } from '@/utils/symbols';
import { buildAllTags, DEFAULT_CUSTOM_TAGS, CUSTOM_TAG_IDS, type TagDef, type CustomTagRaw } from '@/utils/tags';
import { getBackendApiUrl, getBackendWsUrl } from '@/lib/backend-config';

/* Dynamically import the chart so it's client-only (no SSR) */
const AdvancedChart = dynamic(() => import('@/components/AdvancedChart'), {
  ssr: false,
  loading: () => (
    <div className="flex-1 flex items-center justify-center bg-slate-950 min-h-[300px]">
      <div className="flex flex-col items-center gap-3">
        <div className="w-8 h-8 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" />
        <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Initialising Chart Engine…</span>
      </div>
    </div>
  ),
});

interface StockQuote {
  symbol: string;
  name: string;
  price: number;
  change: number;
  changePercent: number;
  marketCap: number;
  volume: number;
  pe: number;
  eps: number;
  cmpBv: number;
  divYield: number;
  promHold: number;
  profitGrowth: number;
  salesGrowth: number;
  isFavourite?: boolean;
  tags?: string[];
  _id?: string;
}

interface BackendStock {
  symbol: string;
  name: string;
  isFavourite?: boolean;
  tags?: string[];
  _id?: string;
}

interface LiveStock {
  symbol: string;
  name: string;
  price: number;
  change: number;
  changePercent: number;
  marketCap: number;
  volume: number;
  pe: number;
  eps: number;
  cmpBv: number;
  divYield: number;
  promHold: number;
  profitGrowth: number;
  salesGrowth: number;
}

interface QuarterlyItem {
  date: string;
  revenue: number;
  costOfRevenue: number;
  grossProfit: number;
  operatingIncome: number;
  netIncome: number;
  eps: number;
}

interface ProfitLossItem {
  date: string;
  revenue: number;
  costOfRevenue: number;
  grossProfit: number;
  operatingIncome: number;
  netIncome: number;
  eps: number;
}

interface BalanceSheetItem {
  date: string;
  totalAssets: number;
  totalLiabilities: number;
  equity: number;
  cash: number;
  debt: number;
  workingCapital: number;
}

interface CashFlowItem {
  date: string;
  operatingCashFlow: number;
  investingCashFlow: number;
  financingCashFlow: number;
  capitalExpenditure: number; 
  netChangeInCash: number; 
  freeCashFlow: number;
}

interface PeerItem {
  symbol: string;
  name: string;
  price: number;
  pe: number;
  marketCap: number;
  divYield: number;
}

interface NewsItem {
  title: string;
  publisher: string;
  link: string;
  date: string;
}

interface VirtualOrder {
  _id?: string;
  symbol: string;
  side: 'buy' | 'sell';
  type: 'market' | 'limit';
  price: number;
  quantity: number;
  status: 'pending' | 'filled' | 'cancelled';
  createdAt?: string;
  filledAt?: string;
}

interface VirtualPosition {
  _id?: string;
  symbol: string;
  side: 'buy' | 'sell';
  averagePrice: number;
  quantity: number;
  currentPrice?: number;
  unrealizedPnL?: number;
  realizedPnL?: number;
}

interface ActiveAlert {
  _id: string;
  symbol: string;
  condition: 'price_above' | 'price_below' | 'price_crosses';
  value: number;
  isActive: boolean;
  isTriggered: boolean;
  createdAt: string;
  triggeredAt?: string;
}

interface WorkspaceTemplate {
  _id: string;
  name: string;
  layout: {
    gridLayout: 1 | 2 | 4 | 6 | 8;
    gridConfigs: Array<{
      symbol: string;
      interval: string;
      style: string;
      indicators: string[];
      drawingsVersion: number;
    }>;
  };
  updatedAt: string;
}

const BACKEND_API_URL = getBackendApiUrl();
const WS_URL = getBackendWsUrl();

const SECTORS_MAP: Record<string, string> = {
  'E2E.NS': 'Tech',
  'AURIONPRO.NS': 'Tech',
  'COFORGE.NS': 'Tech',
  'NETWEB.NS': 'Tech',
  'VOLTAMP.NS': 'Power/Engineering',
  'TDPOWERSYS.NS': 'Power/Engineering',
  'TARIL.NS': 'Power/Engineering',
  'PRECWIRE.NS': 'Power/Engineering',
  'KIRLOSENG.NS': 'Power/Engineering',
  'KEI.NS': 'Power/Engineering',
  'APARINDS.NS': 'Power/Engineering',
  'GVT&D.NS': 'Power/Engineering',
  'CGPOWER.NS': 'Power/Engineering',
  'KRN.NS': 'Power/Engineering',
  'MAZDOCK.NS': 'Defense',
  'ZENTEC.NS': 'Defense',
  'GRSE.NS': 'Defense',
  'PARAS.NS': 'Defense',
  'ASTRAMICRO.NS': 'Defense',
  'DATAPATTNS.NS': 'Defense',
  'MTARTECH.NS': 'Defense',
  'IDEAFORGE.NS': 'Defense',
  'HSCL.NS': 'FMCG/Chemicals',
  'HFCL.NS': 'FMCG/Chemicals',
  'BECTORFOOD.NS': 'FMCG/Chemicals',
  'AEROFLEX.NS': 'FMCG/Chemicals',
  'SHILCTECH.NS': 'Healthcare',
  'APOLLO.NS': 'Healthcare'
};

function TradingTerminalInner() {
  /* ── Core Theme & Workspace States ────────────────────────── */
  const [theme, setTheme] = useState<'dark' | 'light'>('light');
  const [watchlistStocks, setWatchlistStocks] = useState<StockQuote[]>([]);
  const [livePrices, setLivePrices] = useState<Record<string, number>>({});
  
  // Floating Toast State
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
  const showToast = useCallback((message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 4000);
  }, []);

  const [mobileViewTab, setMobileViewTab] = useState<'chart' | 'list'>('chart');

  // Sync state selectors
  const [gridLayout, setGridLayout] = useState<1 | 2 | 4 | 6 | 8>(1);
  const [activeGridIndex, setActiveGridIndex] = useState<number>(0);
  const [syncSymbol, setSyncSymbol] = useState(true);
  const [syncTimeframe, setSyncTimeframe] = useState(true);
  const [syncDrawings, setSyncDrawings] = useState(true);
  const [syncIndicators, setSyncIndicators] = useState(true);
