  /* ── Cloud Workspace Templates ───────────────────────────── */
  const handleSaveWorkspaceLayout = async (e: React.FormEvent) => {
    e.preventDefault();
    const name = newTemplateName.trim();
    if (!name) return;
    
    // Custom set-to-array serialization
    const serializedConfigs = gridConfigs.map(c => ({
