      const rsi14 = Math.min(95, Math.max(8, 35 + (stock.changePercent * 6) + (Math.sin(stock.price) * 12)));
      const sma20 = stock.price * (1 - 0.003 * stock.changePercent);
      const sma50 = stock.price * (1 - 0.009 * stock.changePercent);
      return {
        ...stock,
        rsi14,
        sma20,
        sma50
      };
    });
