  promHold: number;
  profitGrowth: number;
  divYield: number;
}

export const ResultsCards = ({
  stocks,
  loading,
  activeFilters,
}: {
  stocks: StockRow[];
  loading: boolean;
  activeFilters: ActiveFilters;
}) => {
  const router = useRouter();

  if (loading && stocks.length === 0) return (
    <div className="flex items-center justify-center py-20 gap-3 text-slate-400">
      <RefreshCw className="w-5 h-5 animate-spin" />
      <span className="text-sm font-semibold">Loading live NSE/BSE data...</span>
    </div>
  );

  if (stocks.length === 0) return (
    <div className="py-20 text-center text-slate-400 text-sm">No stocks match the active filters.</div>
  );

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-5">
      {stocks.map((s, i) => {
        const pos = s.changePercent >= 0;
        const signal = s.profitGrowth > 15 && s.pe > 0 && s.pe < 30 ? 'BULLISH'
          : s.profitGrowth < 0 ? 'BEARISH'
          : s.pe > 50 ? 'OVERVALUED'
          : 'NEUTRAL';
        const signalClass = signal === 'BULLISH' ? 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20'
          : signal === 'BEARISH' ? 'bg-red-500/10 text-red-500 border-red-500/20'
          : signal === 'OVERVALUED' ? 'bg-orange-500/10 text-orange-500 border-orange-500/20'
          : 'bg-slate-500/10 text-slate-500 border-slate-500/20';

        return (
          <div
            key={i}
            className="bg-slate-50 dark:bg-slate-800/30 border border-slate-200 dark:border-slate-800 rounded-2xl p-5 hover:border-blue-500/30 transition-colors group cursor-pointer"
            onClick={() => router.push(`/watchlist/${encodeURIComponent(s.symbol)}`)}
          >
            <div className="flex justify-between items-start mb-4">
              <div>
                <h3 className="text-lg font-extrabold text-slate-900 dark:text-white flex items-center gap-2">
                  {s.symbol.replace(/\.(NS|BO)$/i, '')}
                  <span className="text-[9px] font-medium text-slate-400">{s.symbol.endsWith('.BO') ? 'BSE' : 'NSE'}</span>
                  <span className={`px-2 py-0.5 rounded-md text-[9px] font-bold uppercase tracking-wider border ${signalClass}`}>
                    {signal}
                  </span>
                </h3>
                <p className="text-xs text-slate-500 mt-0.5 truncate max-w-[180px]">{s.name}</p>
              </div>
              <div className="text-right">
                <div className="text-lg font-bold text-slate-900 dark:text-white">₹{s.price.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</div>
                <div className={`text-xs font-bold mt-0.5 flex items-center justify-end gap-1 ${pos ? 'text-emerald-500' : 'text-red-500'}`}>
                  {pos ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />}
                  {pos ? '+' : ''}{s.changePercent.toFixed(2)}%
                </div>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3 mb-4">
              {[
                { label: 'Market Cap', value: `₹${(s.marketCap / 10000000).toFixed(0)}Cr` },
                { label: 'P/E Ratio', value: s.pe > 0 ? s.pe.toFixed(1) : '--' },
                { label: 'Promoter %', value: s.promHold > 0 ? `${s.promHold.toFixed(1)}%` : '--' },
                { label: 'Profit Gr.', value: s.profitGrowth !== 0 ? `${s.profitGrowth.toFixed(1)}%` : '--', color: s.profitGrowth >= 0 ? 'text-emerald-500' : 'text-red-500' },
              ].map(({ label, value, color }) => (
                <div key={label} className="bg-white dark:bg-slate-900/50 p-3 rounded-xl border border-slate-100 dark:border-slate-800">
                  <div className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mb-1">{label}</div>
                  <div className={`text-sm font-semibold ${color || 'text-slate-700 dark:text-slate-300'}`}>{value}</div>
                </div>
              ))}
            </div>

            <button
              onClick={e => { e.stopPropagation(); router.push(`/watchlist/${encodeURIComponent(s.symbol)}`); }}
              className="w-full py-2.5 bg-blue-500 hover:bg-blue-600 text-white rounded-xl text-xs font-bold transition-all shadow-md active:scale-[0.98] flex items-center justify-center gap-1.5"
            >
              <BarChart2 className="w-3.5 h-3.5" /> Full Analysis
            </button>
          </div>
        );
      })}
    </div>
  );
};

'use client';
import React, { useState, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { Download, ArrowUpDown, ChevronUp, ChevronDown, RefreshCw, TrendingUp, TrendingDown } from 'lucide-react';
import { ActiveFilters } from './FilterSidebar';
import { StockRow } from './screener-utils';

type SortField = keyof StockRow;

export const ResultsTable = ({
  stocks,
  totalUnfiltered,
  loading,
  activeFilters,
  loadingDetail,
}: {
  stocks: StockRow[];
  totalUnfiltered: number;
  loading: boolean;
  activeFilters: ActiveFilters;
  loadingDetail?: string;
}) => {
  const router = useRouter();
  const [sortField, setSortField] = useState<SortField>('marketCap');
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');
  const [page, setPage] = useState(1);
  const PAGE_SIZE = 15;

  const handleSort = (field: SortField) => {
    if (sortField === field) setSortDir((d) => (d === 'asc' ? 'desc' : 'asc'));
    else {
      setSortField(field);
      setSortDir('desc');
    }
    setPage(1);
  };

  const sorted = useMemo(
    () =>
      [...stocks].sort((a, b) => {
        const av = a[sortField] as number;
        const bv = b[sortField] as number;
        if (typeof av === 'number' && typeof bv === 'number') return sortDir === 'asc' ? av - bv : bv - av;
        return 0;
      }),
    [stocks, sortField, sortDir]
  );

  const totalPages = Math.max(1, Math.ceil(sorted.length / PAGE_SIZE));
  const paginated = sorted.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);

  const formatSymbol = (symbol: string) => symbol.replace(/\.(NS|BO)$/i, '');

  const exportCSV = () => {
    const headers = ['Symbol', 'Name', 'Price', 'Change%', 'MCap(Cr)', 'PE', 'EPS', 'CMP/BV', 'DivYield%', 'Promoter%', 'ProfitGr%', 'SalesGr%'];
    const rows = sorted.map((s) => [
      formatSymbol(s.symbol),
      s.name,
      s.price.toFixed(2),
      s.changePercent.toFixed(2),
      (s.marketCap / 10000000).toFixed(2),
      s.pe > 0 ? s.pe.toFixed(2) : 'N/A',
      s.eps > 0 ? s.eps.toFixed(2) : 'N/A',
      s.cmpBv > 0 ? s.cmpBv.toFixed(2) : 'N/A',
      s.divYield.toFixed(2),
      s.promHold.toFixed(2),
      s.profitGrowth.toFixed(2),
      s.salesGrowth.toFixed(2),
    ]);
    const csv = 'data:text/csv;charset=utf-8,' + [headers, ...rows].map((r) => r.map((v) => `"${v}"`).join(',')).join('\n');
    const a = document.createElement('a');
    a.href = encodeURI(csv);
    a.download = 'screener.csv';
    a.click();
  };

  const SortIcon = ({ field }: { field: SortField }) => {
    if (sortField !== field) return <ArrowUpDown className="w-3 h-3 opacity-40" />;
    return sortDir === 'asc' ? <ChevronUp className="w-3 h-3 text-blue-500" /> : <ChevronDown className="w-3 h-3 text-blue-500" />;
  };

  const Th = ({ label, field, right = true }: { label: string; field: SortField; right?: boolean }) => (
    <th
      onClick={() => handleSort(field)}
      className={`p-3 text-xs font-bold text-slate-500 uppercase tracking-wider cursor-pointer hover:text-blue-500 select-none ${right ? 'text-right' : 'text-left'}`}
    >
      <div className={`flex items-center gap-1 ${right ? 'justify-end' : ''}`}>
        {label} <SortIcon field={field} />
      </div>
    </th>
  );

  if (loading && stocks.length === 0)
    return (
      <div className="flex flex-col items-center justify-center py-20 gap-3 text-slate-400">
        <RefreshCw className="w-5 h-5 animate-spin" />
        <span className="text-sm font-semibold">
          {loadingDetail || 'Loading NSE/BSE data from Yahoo Finance…'}
        </span>
      </div>
    );

  return (
    <div className="w-full flex flex-col gap-4">
      <div className="flex items-center justify-between">
        <span className="text-sm font-semibold text-slate-600 dark:text-slate-300">
          Showing <span className="text-blue-500 font-bold">{stocks.length}</span> stocks
          {Object.keys(activeFilters).length > 0 && totalUnfiltered !== stocks.length && (
            <span className="text-slate-400"> (of {totalUnfiltered.toLocaleString()} matching filters)</span>
          )}
        </span>
        <button
          onClick={exportCSV}
          className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300 rounded-lg text-xs font-semibold transition-colors"
        >
          <Download className="w-3.5 h-3.5" /> Export CSV
        </button>
      </div>

      <div className="overflow-x-auto rounded-2xl border border-slate-200 dark:border-slate-800">
        <table className="w-full text-left border-collapse whitespace-nowrap">
          <thead>
            <tr className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-700">
              <Th label="Company" field="name" right={false} />
              <Th label="Price" field="price" />
              <Th label="Change %" field="changePercent" />
              <Th label="MCap (Cr)" field="marketCap" />
              <Th label="P/E" field="pe" />
              <Th label="EPS" field="eps" />
              <Th label="CMP/BV" field="cmpBv" />
              <Th label="Div Yield" field="divYield" />
              <Th label="Promoter %" field="promHold" />
              <Th label="Profit Gr." field="profitGrowth" />
              <Th label="Sales Gr." field="salesGrowth" />
              <th className="p-3 text-xs font-bold text-slate-500 uppercase tracking-wider text-center">Action</th>
            </tr>
          </thead>
          <tbody>
            {paginated.length === 0 ? (
              <tr>
                <td colSpan={12} className="p-12 text-center text-slate-400 text-sm">
                  No stocks match the active filters.
                </td>
              </tr>
            ) : (
              paginated.map((s) => {
                const pos = s.changePercent >= 0;
                return (
                  <tr
                    key={s.symbol}
                    className="border-b border-slate-100 dark:border-slate-800/50 hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors group"
                  >
                    <td className="p-3 sticky left-0 bg-white dark:bg-slate-900 group-hover:bg-slate-50 dark:group-hover:bg-slate-800/30 z-10 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.1)]">
                      <div className="flex flex-col">
                        <span className="font-bold text-sm text-slate-900 dark:text-slate-100">
                          {formatSymbol(s.symbol)}
                          <span className="ml-1 text-[10px] font-medium text-slate-400">
                            {s.symbol.endsWith('.BO') ? 'BSE' : 'NSE'}
                          </span>
                        </span>
                        <span className="text-xs text-slate-500 truncate max-w-[180px]">{s.name}</span>
                      </div>
                    </td>
                    <td className="p-3 text-right font-semibold text-sm">
                      ₹{s.price.toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                    </td>
                    <td className={`p-3 text-right font-bold text-sm ${pos ? 'text-emerald-500' : 'text-red-500'}`}>
                      <span className="flex items-center justify-end gap-1">
                        {pos ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />}
                        {pos ? '+' : ''}
                        {s.changePercent.toFixed(2)}%
                      </span>
                    </td>
                    <td className="p-3 text-right text-sm text-slate-600 dark:text-slate-300">
                      ₹{(s.marketCap / 10000000).toFixed(0)}Cr
                    </td>
                    <td className="p-3 text-right text-sm">{s.pe > 0 ? s.pe.toFixed(1) : '--'}</td>
                    <td className="p-3 text-right text-sm">{s.eps > 0 ? `₹${s.eps.toFixed(2)}` : '--'}</td>
                    <td className="p-3 text-right text-sm">{s.cmpBv > 0 ? s.cmpBv.toFixed(2) : '--'}</td>
                    <td className="p-3 text-right text-sm">{s.divYield > 0 ? `${s.divYield.toFixed(2)}%` : '0%'}</td>
                    <td className="p-3 text-right text-sm">{s.promHold > 0 ? `${s.promHold.toFixed(1)}%` : '--'}</td>
                    <td
                      className={`p-3 text-right text-sm font-semibold ${s.profitGrowth >= 0 ? 'text-emerald-500' : 'text-red-500'}`}
                    >
                      {s.profitGrowth !== 0 ? `${s.profitGrowth.toFixed(1)}%` : '--'}
                    </td>
                    <td
                      className={`p-3 text-right text-sm font-semibold ${s.salesGrowth >= 0 ? 'text-emerald-500' : 'text-red-500'}`}
                    >
                      {s.salesGrowth !== 0 ? `${s.salesGrowth.toFixed(1)}%` : '--'}
                    </td>
                    <td className="p-3 text-center">
                      <button
                        onClick={() => router.push(`/watchlist/${encodeURIComponent(s.symbol)}`)}
                        className="text-xs font-bold text-blue-500 hover:text-blue-600 bg-blue-500/10 hover:bg-blue-500/20 px-3 py-1.5 rounded-lg transition-colors"
                      >
                        Analyse
                      </button>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>

      {totalPages > 1 && (
        <div className="flex items-center justify-between text-xs">
          <span className="text-slate-400 font-semibold">
            {(page - 1) * PAGE_SIZE + 1}–{Math.min(page * PAGE_SIZE, sorted.length)} of {sorted.length}
          </span>
          <div className="flex gap-1">
            <button
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page === 1}
              className="px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-800 disabled:opacity-30 hover:bg-slate-100 dark:hover:bg-slate-800 font-bold"
            >
              ‹
            </button>
            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
              const p = Math.max(1, Math.min(totalPages - 4, page - 2)) + i;
              return (
                <button
                  key={p}
                  onClick={() => setPage(p)}
                  className={`px-3 py-1.5 rounded-lg border font-bold transition-colors ${page === p ? 'bg-blue-500 text-white border-blue-500' : 'border-slate-200 dark:border-slate-800 hover:bg-slate-100 dark:hover:bg-slate-800'}`}
                >
                  {p}
                </button>
              );
            })}
            <button
              onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
              disabled={page === totalPages}
              className="px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-800 disabled:opacity-30 hover:bg-slate-100 dark:hover:bg-slate-800 font-bold"
            >
              ›
            </button>
          </div>
        </div>
      )}
    </div>
  );
};
